INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym są Signals w Angular i czym różnią się od Observables z RxJS?', 'Signals to synchroniczny, reaktywny prymityw wprowadzony w Angular 16+. W przeciwieństwie do Observable, Signal zawsze ma aktualną wartość (nie wymaga subskrypcji) i automatycznie śledzi zależności. Observable jest push-based i asynchroniczny, Signal jest pull-based i synchroniczny. Signals są idealne do stanu UI, Observables do strumieni zdarzeń, HTTP i złożonych transformacji asynchronicznych.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy użyjesz Signal, a kiedy Observable? Podaj konkretne przykłady.', 'Signal: stan komponentu (licznik, formularz, flagi UI), computed values, prosty stan współdzielony między komponentami. Observable: wywołania HTTP, WebSocket, zdarzenia DOM (resize, scroll), złożone łańcuchy operatorów (debounce, retry, race conditions). W praktyce: Signal do „co jest teraz", Observable do „co się dzieje w czasie".', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest computed() i effect() w kontekście Signals?', 'computed() tworzy sygnał pochodny, który automatycznie przelicza wartość gdy zależności się zmienią — jest leniwy i memoizowany. effect() to funkcja uboczna uruchamiana gdy zmienią się odczytywane sygnały. Ważne: effect() nie powinien modyfikować sygnałów (jednokierunkowy przepływ), a computed() nie może mieć side effects. Angular śledzi zależności dynamicznie w runtime.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Change Detection w Angular? Czym różni się Default od OnPush?', 'Default CD sprawdza cały komponent i jego dzieci po każdym zdarzeniu (klik, HTTP, timer). OnPush sprawdza komponent tylko gdy: zmieni się referencja @Input, wyemituje zdarzenie, ręcznie wywołamy markForCheck() lub użyjemy async pipe. OnPush wymaga traktowania danych jako immutable — mutacja obiektu nie wywoła renderowania.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest zoneless Angular i jak działa bez zone.js?', 'Zoneless (Angular 18+) eliminuje zone.js, który patchował wszystkie asynchroniczne API (setTimeout, Promise, addEventListener). Zamiast tego Angular opiera się na Signals do śledzenia zmian. Korzyści: mniejszy bundle (~15 KB mniej), lepsza wydajność, brak nieoczekiwanych cykli CD. Wymaga provideExperimentalZonelessChangeDetection() i konsekwentnego używania Signals.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij hierarchiczny Dependency Injection w Angular.', 'Angular ma drzewo injectorów: root (providedIn: ''root'') → module → element (komponent). Każdy komponent może mieć własny injector (providers: []). Usługi w komponencie tworzą nową instancję dla tego komponentu i jego dzieci. To umożliwia np. osobne instancje FormService w każdym formularzu. Wyszukiwanie zależności idzie w górę drzewa aż do root.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest InjectionToken i kiedy go używasz?', 'InjectionToken to unikalny klucz do wstrzykiwania wartości nieklasowych (string, konfiguracja, funkcja). Używamy gdy nie mamy klasy jako tokenu, np. new InjectionToken<AppConfig>(''APP_CONFIG''). Pozwala na wstrzykiwanie konfiguracji środowiskowej, flag feature toggle czy abstrakcji na localStorage/window bez bezpośredniej zależności.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są multi providers w Angular DI?', 'Multi providers pozwalają zarejestrować wiele wartości pod jednym tokenem — Angular zwróci tablicę wszystkich. Używamy {provide: TOKEN, useValue: val, multi: true}. Klasyczne zastosowanie: HTTP_INTERCEPTORS, gdzie wiele interceptorów jest zarejestrowanych pod jednym tokenem. Kolejność tablicy odpowiada kolejności rejestracji.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są standalone components i dlaczego Angular odchodzi od NgModules?', 'Standalone components (Angular 14+) to samowystarczalne komponenty deklarujące swoje zależności bezpośrednio w imports: []. Eliminują NgModules jako pośrednika. Powód: NgModules dodawały złożoność, utrudniały tree-shaking i lazy loading. Standalone upraszczają mental model — komponent importuje to, czego potrzebuje, bez sztucznego grupowania.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opisz nowy control flow w Angular (@if, @for, @switch, @defer).', '@if/@else zastępuje *ngIf z czytelniejszą składnią bloków. @for wymaga track — funkcji identyfikującej elementy (jak trackBy). @switch to pattern matching. @defer umożliwia lazy loading fragmentów template''u z warunkami (on viewport, on idle, on timer). Nowy flow jest wbudowany w kompilator, nie wymaga importu dyrektyw i generuje wydajniejszy kod.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest @defer i jakie ma triggery?', '@defer to mechanizm leniwego ładowania fragmentów szablonu. Triggery: on idle (gdy przeglądarka jest bezczynna), on viewport (element widoczny), on interaction (klik/focus), on hover, on timer(Xms), when warunek. Wspiera @placeholder, @loading i @error. Każdy @defer tworzy osobny chunk JS — idealny do ciężkich komponentów poniżej fold.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różnią się input(), output() i model() od dekoratorów @Input/@Output?', 'input()/output()/model() to signal-based API (Angular 17+). input() zwraca InputSignal (readonly), output() zwraca OutputEmitterRef. model() tworzy dwukierunkowe wiązanie (ModelSignal — writable signal + event). Korzyści: lepsza typizacja, wymagane inputy (input.required()), łatwiejsze transformacje (transform), integracja z Signals. Dekoratory są legacy.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są różnice między switchMap, mergeMap, concatMap i exhaustMap?', 'switchMap: anuluje poprzednią subskrypcję przy nowej emisji (szukajka, autocomplete). mergeMap: uruchamia równolegle (batch operations, niezależne requesty). concatMap: kolejkuje, czeka na zakończenie poprzedniej (sekwencyjne zapisy). exhaustMap: ignoruje nowe emisje dopóki bieżąca nie zakończy się (submit formularza, zapobieganie podwójnym kliknięciom).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy używasz switchMap a kiedy exhaustMap? Podaj scenariusze.', 'switchMap: pole wyszukiwania (każde nowe wpisanie anuluje poprzedni request), nawigacja (nowa trasa cancelluje starą). exhaustMap: przycisk „Zapisz" (ignoruje kolejne kliknięcia do zakończenia zapisu), logowanie, operacje płatnicze. Użycie switchMap zamiast exhaustMap przy submit = ryzyko wielokrotnego zapisu. Użycie exhaustMap przy search = brak wyników dla ostatniego zapytania.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa lazy loading w Angular i jakie są best practices?', 'Lazy loading ładuje moduły/komponenty na żądanie przez loadComponent/loadChildren w routingu. Angular tworzy osobny chunk JS. Best practices: lazy loaduj każdą feature route, używaj @defer dla ciężkich UI, preloading strategy (PreloadAllModules lub custom) dla przewidywalnych ścieżek. Route-level lazy loading zmniejsza initial bundle nawet o 60-70%.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są route guards i jakie typy istnieją w Angular?', 'Guards to funkcje kontrolujące nawigację. Typy: canActivate (czy użytkownik może wejść), canDeactivate (czy może opuścić, np. niezapisany formularz), canMatch (czy route pasuje), resolve (preload danych). Od Angular 15+ guards to zwykłe funkcje (functional guards), nie klasy. canActivate zwraca boolean, Observable<boolean> lub UrlTree (redirect).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest resolver w routingu i jakie ma wady?', 'Resolver ładuje dane przed aktywacją route — komponent otrzymuje gotowe dane. Wada: blokuje nawigację do zakończenia ładowania, więc użytkownik widzi „zamrożony" UI. Alternatywa: ładować dane w komponencie z @defer/@placeholder lub w ngOnInit z loading state. Resolver ma sens tylko dla krytycznych danych wymaganych do renderowania.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj Reactive Forms z Template-driven Forms. Kiedy co wybrać?', 'Reactive Forms: model formularza w TypeScript (FormGroup/FormControl), synchroniczne, łatwe testowanie, dynamiczne formularze (FormArray). Template-driven: model w szablonie z ngModel, prostsze dla małych formularzy, asynchroniczne walidacje. Reactive Forms wybieramy do złożonych formularzy, dynamicznych pól, zaawansowanej walidacji. Template-driven do prostych formularzy kontaktowych.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Signal Forms i jak się mają do Reactive/Template Forms?', 'Signal Forms to eksperymentalne API (Angular 19+) łączące zalety obu podejść. Używają Signals zamiast Observable do śledzenia stanu. FormControl zyskuje .value jako signal, walidacja jest synchroniczna i reaktywna. Cel: prostota template-driven z mocą reactive, eliminacja .valueChanges na rzecz computed(). Nadal w fazie rozwoju.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa SSR w Angular (@angular/ssr)?', '@angular/ssr (dawniej Angular Universal) renderuje aplikację na serwerze do HTML. Klient otrzymuje gotowy HTML (szybszy FCP/LCP), potem Angular hydruje — podłącza event listenery bez ponownego renderowania DOM. Od Angular 17: partial hydration z @defer, event replay (buforowanie zdarzeń przed hydracją). SSR poprawia SEO i Core Web Vitals.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest hydration w Angular i czym różni się partial hydration?', 'Hydration to proces „ożywiania" statycznego HTML renderowanego na serwerze — Angular dopasowuje DOM do komponentów i podpina interaktywność. Full hydration hydruje całą stronę od razu. Partial hydration (z @defer) hydruje fragmenty na żądanie — np. komentarze dopiero gdy użytkownik scrolluje do nich. Zmniejsza TTI nawet o 50%.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak konfiguruje się TestBed w Angular i po co jest?', 'TestBed to środowisko testowe Angular tworzące mini-moduł testowy. Konfiguracja: TestBed.configureTestingModule({ imports: [KomponentTestowany], providers: [{ provide: Serwis, useValue: mockSerwis }] }). Pozwala nadpisywać zależności mockami, testować interakcje z DOM. Od Angular 15+ preferowane jest testowanie standalone komponentów bez NgModules.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Component Harnesses w Angular Material i dlaczego warto je używać?', 'Component Harness to abstrakcja nad DOM komponentu Material. Zamiast selectorów CSS (kruche na zmiany) używamy API: MatButtonHarness.getText(), MatSelectHarness.open(). Harness jest odporny na zmiany wewnętrznej struktury DOM komponentu. Działa w unit testach i e2e. Własne harnessy tworzymy przez ComponentHarness — dobrze dla shared komponentów.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest trackBy w @for i dlaczego jest wymagany?', 'track w @for identyfikuje elementy listy, by Angular wiedział, które elementy dodać/usunąć/przesunąć zamiast przebudowywać cały DOM. Bez track Angular usunie i stworzy wszystkie elementy od nowa — katastrofa dla wydajności. Najlepiej trackować po unikalnym ID (track item.id), nie po indeksie (track $index niweluje korzyści przy sortowaniu/wstawianiu).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest pure pipe i czemu jest wydajniejszy od metody w szablonie?', 'Pure pipe wykonuje transformację tylko gdy zmieni się referencja wejścia — Angular cachuje wynik. Metoda w szablonie wykonuje się przy każdym cyklu CD (nawet kilkadziesiąt razy/s). Dla listy 100 elementów pipe wykona się 100 razy przy zmianie, metoda 100 × N cykli CD. Impure pipe (pure: false) działa jak metoda — używać ostrożnie.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa virtual scrolling i kiedy go stosujesz?', 'Virtual scrolling (CDK ScrollingModule) renderuje tylko widoczne elementy listy + bufor. Przy 10 000 elementach w DOM będzie np. 20 zamiast 10 000 — drastycznie mniej operacji DOM i pamięci. Stosujemy dla list >100 elementów o stałej/przewidywalnej wysokości. Uwaga: dynamiczna wysokość wymaga itemSize lub autosize, co jest trudniejsze.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest NgRx SignalStore i jak się ma do klasycznego NgRx Store?', 'SignalStore (NgRx 17+) to lekki store oparty na Signals zamiast Redux pattern. Definiujemy store jako signalStore({}) z withState(), withComputed(), withMethods(). Brak actions, reducers, effects — znacznie mniej boilerplate''u. Klasyczny NgRx Store lepszy dla bardzo dużych aplikacji z potrzebą DevTools, entity adaptera i undo/redo.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy serwis z Signals wystarczy zamiast NgRx?', 'Serwis z signal() i computed() wystarczy gdy: stan jest prosty (kilka pól), nie potrzebujesz time-travel debugging, nie masz wielu niezależnych konsumentów ani złożonych efektów ubocznych. NgRx dodaje strukturę wymuszającą przewidywalność w dużych zespołach. Dla >80% aplikacji serwis z Signals jest prostszy i wystarczający. NgRx jest overkillem dla CRUD-ów.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają HTTP Interceptors w Angular i jakie mają zastosowania?', 'Interceptory przechwytują każdy HTTP request/response. Zastosowania: dodawanie tokenu JWT (Authorization header), obsługa błędów 401 (refresh token), retry przy błędach sieci, logowanie, cache''owanie, loading spinner. Od Angular 15+ preferowane są functional interceptors: withInterceptors([authInterceptor]) zamiast klas implementujących HttpInterceptor.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz błędy HTTP globalnie w Angular?', 'Globalny interceptor przechwytuje błędy: catchError w interceptorze sprawdza status. 401 → refresh token i retry. 403 → redirect do /forbidden. 5xx → toast z komunikatem. Dodatkowo ErrorHandler (globalny) łapie niezłapane wyjątki. Ważne: interceptor musi przekazać błąd dalej (throwError) jeśli nie może go obsłużyć, by komponent mógł zareagować lokalnie.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest content projection (ng-content) i jakie są jej rodzaje?', 'Content projection to wstawianie treści z rodzica do dziecka. Rodzaje: single slot (<ng-content>), multi-slot (select="[header]"), conditional (ngProjectAs). Zastosowanie: wrapper komponenty (card, modal, tab). Uwaga: projected content jest tworzony w kontekście rodzica, nie dziecka — zmienny detection i DI działają na poziomie rodzica.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się ng-template od ng-container?', 'ng-template to szablon, który nie jest renderowany domyślnie — wymaga jawnego użycia (*ngIf then/else, ngTemplateOutlet, ViewContainerRef). ng-container to logiczny kontener grupujący elementy bez dodawania elementu do DOM. Użycie: ng-container gdy potrzebujemy strukturalnej dyrektywy bez wrapper div, ng-template do reużywalnych fragmentów szablonu.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest ngTemplateOutlet i jak go używasz?', 'ngTemplateOutlet dynamicznie renderuje ng-template w danym miejscu. Składnia: <ng-container *ngTemplateOutlet="szablon; context: {$implicit: dane}">. Pozwala na renderowanie różnych szablonów w zależności od warunku, tworzenie konfigurowalnych komponentów (np. custom row template w tabeli). Context przekazuje dane do szablonu.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest ViewChild i ContentChild? Czym się różnią?', 'ViewChild szuka elementu w szablonie komponentu (jego własny template). ContentChild szuka elementu w projected content (treść przekazana przez rodzica). ViewChild dostępny od AfterViewInit, ContentChild od AfterContentInit. Signal-based: viewChild()/contentChild() zwracają sygnały, dostępne natychmiast bez lifecycle hooks.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa providedIn: ''root'' i czym różni się od providers w komponencie?', 'providedIn: ''root'' tworzy singleton na poziomie root injector — jedna instancja w całej aplikacji, tree-shakeable (usuwana jeśli nieużywana). providers w komponencie tworzy nową instancję dla każdej instancji komponentu i jego dzieci. Użyj root dla globalnych serwisów (auth, http), providers w komponencie dla izolowanego stanu (formularz, wizard).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest inject() function i czym różni się od constructor injection?', 'inject() to funkcja dostępna w kontekście DI (konstruktor, factory, guard). Pozwala pobierać zależności bez deklarowania ich w konstruktorze. Korzyści: działa w funkcjach (functional guards, interceptors), ułatwia composable patterns, mniej boilerplate. Ograniczenie: musi być wywołana w injection context — nie w setTimeout czy subscribe.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest linkedSignal() i kiedy go użyjesz?', 'linkedSignal() (Angular 19+) to writable signal, który resetuje się gdy zmieni się źródłowy signal. Przykład: lista produktów (signal) i wybrany produkt (linkedSignal) — po zmianie listy wybrany produkt resetuje się do pierwszego. Rozwiązuje problem „stale state" bez ręcznego effect(). Jest to computed + WritableSignal w jednym.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest resource() API w Angular i do czego służy?', 'resource() (Angular 19+) to reaktywny prymityw do asynchronicznego ładowania danych oparty na Signals. Definiujesz request (signal z parametrami) i loader (async function). resource automatycznie wywołuje loader gdy request się zmieni. Zwraca signal z value, status, error. Zastępuje ręczne subskrypcje w ngOnInit i loading/error boilerplate.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz formularz wielokrokowy (wizard) w Angular?', 'Podejścia: 1) Jeden FormGroup z zagnieżdżonymi grupami per krok, walidacja per krok. 2) Osobne FormGroup per krok + serwis trzymający stan. 3) Stepper z CDK. Kluczowe: canDeactivate guard chroni przed utratą danych, serwis z signal przechowuje stan między krokami, walidacja lazy (waliduj krok przy przejściu dalej, nie od razu).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest HostListener i HostBinding? Czy nadal ich używamy?', 'HostListener dekoruje metodę reagującą na zdarzenia host elementu. HostBinding binduje właściwość DOM hosta. Od Angular 15+ preferowane jest host: {} w metadanych komponentu — czytelniejsze i tree-shakeable. Przykład: host: { ''(click)'': ''onClick()'', ''[class.active]'': ''isActive()'' }. Dekoratory nadal działają, ale nowy sposób jest lepszy.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementujesz globalny error handler w Angular?', 'Implementujesz ErrorHandler i nadpisujesz handleError(). Rejestrujesz: { provide: ErrorHandler, useClass: GlobalErrorHandler }. W handleError logujesz błąd do serwisu (Sentry, LogRocket), wyświetlasz toast. Ważne: HttpErrors łatwiej obsługiwać w interceptorze — ErrorHandler łapie głównie błędy runtime JS. Unikaj throwError w ErrorHandler — tworzy pętlę.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest DestroyRef i takeUntilDestroyed w Angular?', 'DestroyRef (Angular 16+) to injectable referencja do lifecycle destroy komponentu/serwisu. takeUntilDestroyed() automatycznie odsubskrybowuje Observable przy zniszczeniu. Zastępuje ręczne ngOnDestroy + Subject + takeUntil. Użycie: this.http.get(''/api'').pipe(takeUntilDestroyed()).subscribe(). Musi być wywołane w injection context (konstruktor).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zoptymalizujesz dużą aplikację Angular pod kątem wydajności?', 'Checklist: OnPush na wszystkich komponentach, Signals zamiast zwykłych properties, lazy loading routes + @defer, trackBy w @for, pure pipes zamiast metod w szablonie, virtual scrolling dla list, preloadingStrategy, budowanie z --optimization, analiza bundle (source-map-explorer). Profiluj z Angular DevTools — nie optymalizuj na ślepo.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Angular DevTools i jak pomaga w debugowaniu?', 'Angular DevTools to rozszerzenie Chrome do profilowania i debugowania. Pozwala: przeglądać drzewo komponentów z ich stanem, mierzyć czas change detection per komponent, wykrywać niepotrzebne cykle CD, inspektować DI tree. Profiler pokazuje ile czasu każdy komponent „kosztuje" w cyklu CD — kluczowe do znalezienia bottlenecków.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest ng-container i kiedy go stosujesz?', 'ng-container to logiczny element nie renderujący niczego w DOM. Stosujemy gdy: potrzebujemy wielu dyrektyw strukturalnych na jednym elemencie (nie można dwóch *ngIf na jednym), chcemy zastosować *ngFor bez dodatkowego div, grupujemy elementy dla *ngIf. Alternatywa w nowym control flow: @if i @for nie wymagają ng-container.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa dependency injection z useFactory?', 'useFactory pozwala tworzyć instancję serwisu z niestandardową logiką. Przykład: { provide: API_URL, useFactory: (env: Env) => env.production ? ''prod.api'' : ''dev.api'', deps: [ENV_TOKEN] }. Przydatne do warunkowej konfiguracji, tworzenia instancji z parametrami runtime, integracji z kodem spoza Angular (np. firebase).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest toSignal() i toObservable()? Kiedy konwertujesz?', 'toSignal() konwertuje Observable na Signal — wymaga wartości początkowej (initialValue) lub requireSync. toObservable() konwertuje Signal na Observable. Konwertujesz gdy: używasz RxJS serwisu w Signals komponentcie (toSignal), lub Signal w bibliotece wymagającej Observable. Uwaga: toSignal() subskrybuje od razu i zarządza subskrypcją automatycznie.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz strategie preloadingu modułów w Angular?', 'Wbudowane: NoPreloading (domyślna — nic nie preloaduje), PreloadAllModules (ładuje wszystkie lazy modules po starcie). Custom strategy: możesz preloadować na podstawie route data, np. data: { preload: true }. QuicklinkStrategy (third-party) preloaduje tylko trasy widoczne jako linki na stronie. Wybór zależy od rozmiaru aplikacji i wzorców nawigacji.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij różnicę między forRoot() i forChild().', 'forRoot() rejestruje serwisy i konfigurację na poziomie root — wywoływane raz w AppModule. forChild() rejestruje tylko routes/features bez powielania serwisów. Klasyczny przykład: RouterModule.forRoot(routes) w app, RouterModule.forChild(routes) w feature modules. Bez tego rozróżnienia lazy-loaded moduły tworzyłyby duplikaty singletonów.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testujesz komponent z zależnościami w Angular?', 'W TestBed nadpisujesz prawdziwe serwisy mockami: providers: [{ provide: UserService, useValue: jasmine.createSpyObj(''UserService'', [''getUser'']) }]. Dla HTTP: HttpClientTestingModule + HttpTestingController do mockowania requestów. Dla routera: RouterTestingModule. Alternatywnie: testuj komponent bez TestBed jako zwykłą klasę, wstrzykując mocki ręcznie.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest canMatch guard i czym różni się od canActivate?', 'canMatch decyduje czy route w ogóle „pasuje" — jeśli zwróci false, router szuka dalej w tablicy routes. canActivate blokuje nawigację po dopasowaniu route. canMatch pozwala mieć tę samą ścieżkę z różnymi komponentami: {path: ''dashboard'', canMatch: [isAdmin], component: AdminDashboard}, {path: ''dashboard'', component: UserDashboard}.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak realizujesz komunikację między komponentami w Angular?', 'Sposoby: 1) @Input/@Output (rodzic-dziecko), 2) Serwis z Subject/Signal (dowolna relacja), 3) ViewChild (rodzic czyta dziecko), 4) Content projection (przekazywanie szablonów), 5) Router state (parametry, query params, data). Dla prostej komunikacji rodzic-dziecko: Input/Output. Dla współdzielonego stanu: serwis z Signals. Unikaj event busów.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest async pipe i dlaczego jest preferowany?', 'async pipe automatycznie subskrybuje Observable/Promise i wyświetla wartość w szablonie. Kluczowa zaleta: automatyczna odsubskrypcja przy zniszczeniu komponentu — brak memory leaks. Działa z OnPush (triggeruje CD). Wada: wielokrotne użycie tego samego Observable w szablonie = wielokrotna subskrypcja. Rozwiązanie: *ngIf="obs$ | async as value" lub Signals.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz techniki zapobiegania memory leaks w Angular?', 'Techniki: 1) takeUntilDestroyed() — najnowsze, 2) async pipe — automatyczna odsubskrypcja, 3) Subject + takeUntil + ngOnDestroy — klasyczne, 4) DestroyRef.onDestroy(), 5) Signals (nie wymagają subskrypcji). Najczęstsze źródła leaków: subskrypcje w subscribe() bez cleanup, setInterval bez clearInterval, addEventListener bez removeEventListener.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Renderer2 i kiedy go używasz zamiast bezpośredniego DOM?', 'Renderer2 to abstrakcja nad DOM API zapewniająca kompatybilność z SSR i Web Workers (gdzie nie ma document). Zamiast element.style.color = ''red'' → renderer.setStyle(el, ''color'', ''red''). W praktyce od Angular 17+ rzadko potrzebny — Signals i template binding obsługują większość przypadków. Używaj gdy musisz dynamicznie manipulować DOM spoza szablonu.', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa router events i do czego można je wykorzystać?', 'Router emituje zdarzenia: NavigationStart, NavigationEnd, NavigationCancel, NavigationError, GuardsCheckStart/End, ResolveStart/End. Zastosowania: globalny loading spinner (NavigationStart → show, NavigationEnd → hide), analityka (NavigationEnd → trackPageView), breadcrumbs. Subskrybuj: router.events.pipe(filter(e => e instanceof NavigationEnd)).', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest afterNextRender i afterRender w Angular?', 'afterNextRender() wykonuje callback po następnym renderowaniu (jednorazowo). afterRender() wykonuje callback po każdym renderowaniu. Zastępują ngAfterViewInit dla inicjalizacji DOM (np. integracja z bibliotekami JS). Działają tylko w przeglądarce (nie na serwerze) — bezpieczne dla SSR. Fazy: read (odczyt DOM), write (zapis DOM) — unikanie layout thrashing.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz dynamiczne komponenty w Angular?', 'Nowoczesne podejście: @if z dynamicznym komponentem lub NgComponentOutlet. Klasycznie: ViewContainerRef.createComponent(). NgComponentOutlet przyjmuje typ komponentu i renderuje go dynamicznie: <ng-container *ngComponentOutlet="activeComponent; inputs: {data: value}">. Przydatne do tabów, dashboardów, pluginów — komponent wybierany w runtime.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest environment injection (inject) vs constructor injection?', 'Oba mechanizmy dostarczają zależności z tego samego DI tree. inject() (funkcyjna) działa w injection context — konstruktor, factory, route guard/resolver. Constructor injection wymaga deklaracji parametrów. inject() jest lepsza w standalone world: mniej boilerplate, działa w functional guards i interceptors, umożliwia tworzenie composable helper functions.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest APP_INITIALIZER i jak go stosujesz?', 'APP_INITIALIZER to multi-provider token wykonywany przed uruchomieniem aplikacji. Zwraca Promise lub Observable — Angular czeka na zakończenie. Zastosowania: ładowanie konfiguracji z serwera, sprawdzanie sesji, ładowanie tłumaczeń. Uwaga: zbyt wolny initializer blokuje start aplikacji. Od Angular 16+: provideAppInitializer(() => inject(ConfigService).load()).', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym jest Virtual DOM i jak działa rekoncyliacja w React?', 'Virtual DOM to lekka kopia prawdziwego DOM w pamięci. Przy zmianie stanu React tworzy nowe vDOM, porównuje je ze starym (diffing) i aplikuje minimalne zmiany do prawdziwego DOM (reconciliation). Algorytm zakłada: różne typy elementów = różne drzewa, key identyfikuje elementy listy. Złożoność O(n) dzięki heurystykom zamiast O(n³).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Fiber architecture w React?', 'Fiber to przepisany od podstaw silnik renderowania (React 16+). Zamienia rekurencyjny, synchroniczny rendering na iteracyjny, przerywalny. Każdy komponent to fiber node z informacjami o stanie, efektach i priorytecie. Pozwala React przerwać renderowanie, obsłużyć ważniejszą aktualizację (np. input użytkownika) i wrócić. Jest fundamentem concurrent features.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij różnicę między useState a useReducer. Kiedy co wybrać?', 'useState: prosty stan (boolean, string, number). useReducer: złożony stan z wieloma powiązanymi wartościami, logika przejść między stanami. useReducer gdy: nowy stan zależy od poprzedniego w złożony sposób, wiele akcji modyfikuje ten sam stan, chcesz wyciągnąć logikę do testowania. useState wystarczy dla >90% przypadków. useReducer to useState pod spodem.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są zasady hooks? Dlaczego nie można wywoływać ich warunkowo?', 'Zasady: 1) Wywołuj tylko na najwyższym poziomie (nie w if/for/try), 2) Wywołuj tylko w komponentach funkcyjnych lub custom hookach. Powód: React identyfikuje hooki po kolejności wywołania w danym renderze. Jeśli warunek pominie hook, kolejność się przesunie i React przypisze stan do złego hooka. Lint reguła: react-hooks/rules-of-hooks.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij useEffect — dependency array, cleanup, typowe błędy.', 'useEffect(fn, deps) wykonuje efekt uboczny po renderze. [] = raz (mount), [dep] = gdy dep się zmieni, brak = co render. Cleanup (return () => {}) uruchamia się przed kolejnym efektem i przy unmount. Typowe błędy: brak deps (nieskończona pętla), obiekt/tablica w deps (nowa referencja = ciągłe wywołania), brak cleanup (memory leak: subskrypcje, timery).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useRef i jakie ma zastosowania poza DOM?', 'useRef zwraca mutable obiekt {current: value} persystentny między renderami. Zastosowania: 1) referencja DOM (ref={inputRef}), 2) przechowywanie wartości bez triggerowania rerendera (previous value, timer ID, flagi), 3) utrzymywanie mutable wartości w closures. Kluczowe: zmiana .current NIE powoduje rerenderowania — to nie stan, to „skrzynka".', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy useMemo i useCallback naprawdę pomagają? Kiedy szkodzą?', 'useMemo/useCallback pomagają gdy: memoizowany komponent dziecko (React.memo) otrzymuje obiekt/funkcję jako prop, kosztowna kalkulacja w renderze, stabilna referencja potrzebna w deps. Szkodzą gdy: koszt memoizacji > koszt rekalkulacji (proste obliczenia), wartość nie jest przekazywana niżej. Premature optimization — profileuj najpierw, memoizuj potem.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa React.memo i jakie ma ograniczenia?', 'React.memo to HOC memoizujący komponent — nie rerenderuje go jeśli props się nie zmieniły (shallow compare). Ograniczenia: porównuje referencje, nie wartości (nowy obiekt/tablica = rerender), nie pomaga jeśli komponent pobiera kontekst (zmiana kontekstu = rerender mimo memo). Accepts custom comparator: React.memo(Comp, arePropsEqual).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij Context API — kiedy używać, jakie są pułapki?', 'Context przekazuje dane przez drzewo bez prop drilling. Pułapki: KAŻDA zmiana wartości context rerenduje WSZYSTKICH konsumentów, nawet jeśli używają tylko części danych. Rozwiązania: dziel context na mniejsze, memoizuj value obiektu (useMemo), użyj use-context-selector. Nie używaj Context jako state managera dla częstych aktualizacji (np. pozycja myszy).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Suspense i Error Boundaries? Jak współpracują?', 'Suspense wyświetla fallback UI gdy dziecko się ładuje (lazy component, data fetching z use()). Error Boundary łapie błędy w renderze dzieci i wyświetla fallback error UI. Razem tworzą kompletny wzorzec: Suspense + Error Boundary owijają komponent. Suspense obsługuje loading, EB obsługuje error, komponent obsługuje success. Deklaratywna obsługa async stanów.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są React Server Components (RSC)? Jak działają?', 'RSC renderują się na serwerze i wysyłają do klienta jako gotowe vDOM (nie HTML). Nie mają stanu, hooków ani event handlerów. Mogą bezpośrednio czytać bazę danych, system plików. Korzyść: zero JS w bundlu klienta dla RSC. RSC mogą importować Client Components, ale nie odwrotnie. Fundamentalna zmiana: komponenty dzielą się na server/client boundary.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się Server Component od Client Component?', 'Server Component: renderowany na serwerze, brak useState/useEffect, dostęp do backendu, 0 KB JS klienta. Client Component: oznaczony ''use client'', renderowany w przeglądarce, ma pełne API Reacta. Granica: gdy potrzebujesz interaktywności (onClick, useState) — Client. Statyczny content, data fetching — Server. Domyślnie w Next.js App Router wszystko jest Server.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są Server Actions i jak ich używasz?', 'Server Actions to asynchroniczne funkcje oznaczone ''use server'' wykonywane na serwerze. Wywoływane z Client Components przez formularz (action={}) lub bezpośrednio. Zastępują API routes dla mutacji. React automatycznie serializuje dane formularza. Obsługują optimistic updates z useOptimistic. Działają bez JS po stronie klienta (progressive enhancement).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest hook use() w React 19?', 'use() to specjalny hook, który może być wywoływany warunkowo (wyjątek od rules of hooks). Przyjmuje Promise lub Context. Z Promise: integruje się z Suspense (suspenduje komponent do resolve). Z Context: alternatywa dla useContext z conditional calling. use(promise) zastępuje useState + useEffect do data fetchingu w nowym modelu RSC.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useTransition i kiedy go stosujesz?', 'useTransition oznacza aktualizację stanu jako „niski priorytet" — React może ją przerwać na rzecz pilniejszych (np. input). Zwraca [isPending, startTransition]. Zastosowanie: filtrowanie dużej listy, przełączanie tabów z ciężkim renderem, nawigacja. Input aktualizuje się natychmiast, wynik filtrowania „dogania". Unika zamrożenia UI przy kosztownych rerendera.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useDeferredValue i jak różni się od useTransition?', 'useDeferredValue opóźnia aktualizację wartości — React najpierw renderuje ze starą wartością, potem z nową w tle. useTransition opakowuje setState, useDeferredValue opakowuje wartość. Użyj useDeferredValue gdy nie kontrolujesz setState (np. prop z rodzica). useTransition gdy wywołujesz setState. Oba korzystają z concurrent rendering do płynnego UI.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak tworzyć custom hooks? Podaj zasady i wzorce.', 'Custom hook to funkcja zaczynająca się od „use" używająca innych hooks. Zasady: wydzielaj logikę reużywalną (useForm, useFetch, useDebounce), zwracaj tuple/obiekt, obsługuj cleanup. Wzorce: useLocalStorage (synchronizacja ze storage), useMediaQuery (responsywność), useClickOutside (zamykanie dropdownu). Custom hook to composability Reacta — odpowiednik mixinów, ale bez ich wad.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest concurrent rendering w React?', 'Concurrent rendering to zdolność Reacta do przygotowywania wielu wersji UI jednocześnie. React może przerwać render, obsłużyć ważniejsze zadanie i wrócić. Nie jest multithreading — to kooperatywny scheduling na jednym wątku. Włączany przez createRoot(). Umożliwia: useTransition, useDeferredValue, Suspense streaming. Eliminuje „zamrażanie" UI przy ciężkich aktualizacjach.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dlaczego key jest ważny w listach? Co się stanie bez niego lub z index jako key?', 'Key identyfikuje element listy między renderami. Bez key React porównuje po pozycji — przy wstawieniu elementu na początek przerenderowuje wszystko. Z index: ten sam problem przy sortowaniu/usuwaniu — stan komponentu przypisany do złego elementu. Używaj stabilnego, unikalnego ID. Index jako key bezpieczny tylko dla list statycznych, niesortowalnych.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różnią się controlled i uncontrolled components?', 'Controlled: wartość zarządzana przez React state (value={state} + onChange). Każda zmiana przechodzi przez setState. Uncontrolled: wartość zarządzana przez DOM (defaultValue + useRef). Controlled daje pełną kontrolę (walidacja na żywo, formatowanie, warunkowe zmiany). Uncontrolled jest prostszy (integracja z bibliotekami, pliki). Unikaj mieszania w jednym input.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa code splitting z React.lazy i Suspense?', 'React.lazy(() => import(''./Component'')) tworzy dynamiczny import — osobny chunk JS ładowany na żądanie. Suspense opakowuje lazy komponent i wyświetla fallback podczas ładowania. Typowe użycie: lazy loading routes, ciężkie moduły (edytor, wykresy). Uwaga: React.lazy działa tylko z default exports. Named exports: React.lazy(() => import(''./X'').then(m => ({default: m.Named}))).', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj Zustand, Jotai i TanStack Query jako state management.', 'Zustand: globalny store, minimalne API (create + hook), idealny do client state (UI, auth). Jotai: atomowy (bottom-up), każdy atom to niezależny kawałek stanu, lepszy do wielu izolowanych wartości. TanStack Query: server state management (cache, refetch, stale-while-revalidate), nie jest zamiennikiem Zustand — uzupełnieniem. Często: TanStack Query (server) + Zustand (client).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testujesz komponenty React z React Testing Library?', 'RTL testuje z perspektywy użytkownika: render(<Comp />), screen.getByRole(''button''), fireEvent.click() / userEvent.click(). Nie testuj implementacji (stanu, instancji). Szukaj po roli (getByRole), tekście (getByText), labelu (getByLabelText). Mockuj API z MSW (Mock Service Worker). Asynchroniczne: await screen.findByText(). RTL wymusza dobre praktyki dostępności.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest MSW (Mock Service Worker) i dlaczego jest lepszy od mocków fetch?', 'MSW interceptuje requesty na poziomie sieci (Service Worker w przeglądarce, interceptor w Node). Korzyści: ten sam mock dla testów i dev, realistyczne zachowanie (opóźnienia, statusy), kod produkcyjny nie wie o mocku. Vs mockowanie fetch/axios: kruche, nie testuje pełnego flow, trzeba mockować implementację. MSW testuje integrację z prawdziwym kodem HTTP.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj Next.js App Router z Pages Router.', 'App Router (Next 13+): RSC domyślnie, nested layouts, Suspense streaming, Server Actions, fine-grained caching. Pages Router: klasyczny SSR/SSG z getServerSideProps/getStaticProps, _app.tsx, _document.tsx. App Router jest przyszłością — głębsza integracja z React 18+ features. Pages Router stabilniejszy, prostszy, ale nie będzie rozwijany. Migracja jest stopniowa — oba mogą współistnieć.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają layouts w Next.js App Router?', 'Layout to komponent opakowujący stronę, persystentny między nawigacjami (nie rerenderuje się). layout.tsx w folderze stosuje się do wszystkich stron w tym folderze i podfolderach. Nested layouts: app/layout.tsx (root) > app/dashboard/layout.tsx (dashboard). Idealne do nawigacji, sidebar, kontekstów. Template.tsx to layout bez persystencji — rerenderuje się przy nawigacji.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useOptimistic w React 19?', 'useOptimistic pozwala natychmiast wyświetlić oczekiwany wynik akcji zanim serwer potwierdzi. Np. przy wysyłaniu komentarza — pojawia się od razu, a po odpowiedzi serwera stan się synchronizuje. Jeśli akcja się nie powiedzie, React automatycznie cofnie optymistyczną aktualizację. Drastycznie poprawia perceived performance aplikacji.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak unikasz prop drilling w React? Porównaj podejścia.', 'Sposoby: 1) Context API (prosty, ale rerendery), 2) Composition (przekazywanie JSX jako children/props), 3) Zustand/Jotai (zewnętrzny store), 4) Component composition (render props, compound components). Często najlepsze: composition pattern — zamiast przekazywać dane przez 5 poziomów, przenieś komponent wyżej i przekaż jako children. Unikaj Context dla częstych zmian.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są compound components pattern w React?', 'Compound components to wzorzec gdzie rodzic i dzieci współdzielą implicit state. Przykład: <Select><Option value="a">A</Option></Select>. Implementacja: Context w rodzicu, children go konsumują. Korzyści: deklaratywne API, elastyczny układ, enkapsulacja logiki. Używane w: Headless UI, Radix, Reach UI. Alternatywa dla „prop hell" w jednym mega-komponencie.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak React batching działa w v18+ i czym różni się od v17?', 'W React 17 batching (łączenie setState) działał tylko w event handlerach Reacta. W React 18+ automatic batching łączy WSZYSTKIE aktualizacje stanu — w setTimeout, Promises, natywnych event handlerach. Jeden render zamiast kilku. Jeśli potrzebujesz natychmiastowego rerenderowania: flushSync(() => setState(val)). Batching to bezpłatna optymalizacja v18.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest forwardRef i kiedy jest potrzebny?', 'forwardRef przekazuje ref z rodzica do wewnętrznego DOM elementu komponentu. Bez niego ref wskazuje na instancję komponentu (która w funkcyjnym nie istnieje). Potrzebny: biblioteki komponentów (button, input), animacje (ref do DOM), integracja z imperatywnym kodem. W React 19: ref jest zwykłym propem — forwardRef nie jest już potrzebny.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useImperativeHandle i kiedy go stosujesz?', 'useImperativeHandle pozwala kontrolować co rodzic widzi przez ref. Zamiast pełnego DOM elementu eksponujesz ograniczone API: useImperativeHandle(ref, () => ({ focus: () => inputRef.current.focus(), reset })). Użycie: komponenty formularzy z custom API, edytory, playery. Chroni enkapsulację — rodzic nie ma dostępu do całego DOM.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz formularze w React? Porównaj podejścia.', 'Podejścia: 1) Controlled z useState (najprostsze, pełna kontrola), 2) react-hook-form (uncontrolled, minimalne rerendery, świetna walidacja), 3) Formik (controlled, popularny ale ciężki), 4) Server Actions z formData (progressive enhancement). react-hook-form jest najczęstszym wyborem: najlepsza wydajność, integracja z zod/yup do walidacji schematów.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest render prop pattern i czy nadal jest aktualny?', 'Render prop to wzorzec przekazywania funkcji renderującej jako prop/children: <Mouse render={({x,y}) => <Cat x={x} y={y}/>}/>. Był popularny pre-hooks do reużywania logiki. Dziś custom hooks lepiej rozwiązują ten problem. Render props nadal przydatne: dynamiczne sloty w komponentach UI, biblioteki (TanStack Table, Downshift), gdy potrzebujesz JSX callback.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak profilować i optymalizować wydajność React?', 'Narzędzia: React DevTools Profiler (flamegraph, ranked view, „why did this render"), Chrome DevTools Performance tab, why-did-you-render library. Optymalizacje: React.memo dla czystych komponentów, useMemo/useCallback dla stabilnych referencji, lazy loading, virtualizacja list (react-window), debounce inputów. Zasada: nie optymalizuj bez pomiaru — profileuj najpierw.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest React Compiler (dawniej React Forget)?', 'React Compiler to kompilator automatycznie memoizujący komponenty i hooki w build time. Eliminuje potrzebę ręcznego useMemo, useCallback, React.memo. Analizuje kod i dodaje memoizację tam gdzie potrzeba. Działa z istniejącym kodem (opt-in). Wymaga przestrzegania reguł Reacta (pure render, rules of hooks). Dostępny eksperymentalnie w React 19+.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Suspense streaming w Next.js?', 'Suspense streaming wysyła HTML fragmentami. Serwer natychmiast wysyła shell (layout + fallback Suspense), potem streamuje gotowe fragmenty w miarę ich renderowania. Przeglądarka „wstrzykuje" je w placeholder. Korzyść: szybki TTFB, progresywne ładowanie. Implementacja: opakowujesz async komponent w <Suspense fallback={<Skeleton/>}> i React automatycznie streamuje.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useId i do czego służy?', 'useId generuje unikalne ID stabilne między serwerem a klientem. Użycie: łączenie label z input (htmlFor={id}), aria-describedby, unikalne ID w listach komponentów. Dlaczego nie Math.random()? — różny wynik na serwerze i kliencie = hydration mismatch. useId gwarantuje identyczne ID w SSR i CSR. Nie używaj do key w listach.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak realizujesz autentykację w Next.js App Router?', 'Podejścia: 1) Middleware (middleware.ts) — sprawdza cookie/token przed każdym request. 2) Layout Server Component — sprawdza sesję, redirect jeśli brak. 3) NextAuth.js/Auth.js — pełne rozwiązanie z providerami. Cookie-based session jest preferowana (httpOnly, secure). Middleware do route protection, Server Components do conditional rendering, Server Actions do login/logout.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest stale-while-revalidate w kontekście data fetchingu?', 'SWR to strategia cache: zwróć stale (przestarzałe) dane z cache natychmiast, w tle pobierz świeże, po pobraniu zaktualizuj UI. Użytkownik widzi dane od razu bez loadera. Implementacja: TanStack Query (staleTime, cacheTime), SWR library, Next.js fetch cache. Idealne do danych zmieniających się rzadko (profil, lista produktów), nie do real-time (chat).', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest useFormStatus i jak go używasz z Server Actions?', 'useFormStatus() zwraca {pending, data, method, action} dla najbliższego nadrzędnego <form>. pending=true podczas trwania Server Action — idealny do disable buttona i wyświetlania spinnera. Musi być w komponencie dziecku formularza (nie w tym samym komponencie co form). Eliminuje ręczne zarządzanie loading state dla formularzy.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz cache''owaniem w Next.js App Router?', 'Next.js ma 4 warstwy cache: 1) Request Memoization (deduplikacja fetch w jednym renderze), 2) Data Cache (persystentny cache fetch na serwerze), 3) Full Route Cache (statyczny HTML), 4) Router Cache (client-side cache segmentów). Kontrola: revalidate (ISR), cache: ''no-store'', revalidatePath/revalidateTag. Domyślnie agresywne cache''owanie — musisz świadomie invalidować.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest hydration mismatch i jak go unikasz?', 'Hydration mismatch to różnica między HTML z serwera a tym co React renderuje na kliencie. Powody: Math.random(), Date.now(), window/localStorage, warunkowy render po stronie klienta. Rozwiązania: useEffect dla client-only kodu, suppressHydrationWarning (ostrożnie), useId zamiast random. Next.js: dynamic(() => import(''./Comp''), {ssr: false}) dla client-only komponentów.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz infinite scroll w React?', 'Podejścia: 1) Intersection Observer API — obserwuj element „sentinel" na dole listy, fetch przy widoczności. 2) react-intersection-observer + TanStack Query (useInfiniteQuery). 3) Virtualizacja (@tanstack/react-virtual) dla wydajności. Kluczowe: useInfiniteQuery zarządza stronami, hasNextPage/fetchNextPage, loading/error states. Nie zapomnij o scroll restoration.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest portal w React i kiedy go używasz?', 'ReactDOM.createPortal(children, domNode) renderuje dzieci w innym miejscu DOM niż rodzic. Zastosowania: modale, tooltipy, dropdown menu — elementy, które muszą być nad innymi (z-index) lub poza overflow:hidden rodzica. Ważne: event bubbling nadal działa w React tree (nie DOM tree) — klik w portalu bąbelkuje do React rodzica.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz dark mode w React?', 'Podejścia: 1) CSS custom properties + atrybut data-theme na html, toggle zmienia atrybut. 2) Tailwind dark: z class strategy. 3) CSS prefers-color-scheme media query. Persystencja: localStorage + system preference jako default. SSR: cookie zamiast localStorage (uniknięcie flash). next-themes w Next.js rozwiązuje SSR flash. Kontekst lub Zustand do globalnego stanu.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Higher-Order Components (HOC)? Czy nadal ich używamy?', 'HOC to funkcja przyjmująca komponent i zwracająca nowy z dodaną funkcjonalnością: withAuth(Dashboard). Problemy: wrapper hell, name collision, trudność śledzenia propsów. Dziś custom hooks lepiej rozwiązują reużywanie logiki. HOC nadal spotykane: connect() z Redux (legacy), withRouter, w bibliotekach. Preferuj hooks + composition nad HOC.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz globalne błędy w React?', 'Error Boundary (class component z getDerivedStateFromError + componentDidCatch) łapie błędy w renderze dzieci. Nie łapie: event handlerów, async kodu, SSR, samego EB. Dla event handlerów: try/catch. Dla async: .catch() lub error state. Architektura: Root EB (generic fallback) + granularne EB per feature (izolacja błędów). react-error-boundary upraszcza implementację.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useLayoutEffect i czym różni się od useEffect?', 'useLayoutEffect wykonuje się synchronicznie PO DOM mutations ale PRZED paintem przeglądarki. useEffect wykonuje się asynchronicznie po paincie. useLayoutEffect do: pomiarów DOM (getBoundingClientRect), zapobiegania migotaniu (flash of unstyled content), animacji wymagających natychmiastowej zmiany. Użycie useLayoutEffect nadmiernie blokuje painting — używaj oszczędnie.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają slot patterns w React (children, render props, named slots)?', 'React nie ma formalnych slotów jak Vue/Angular. Realizacja: 1) children prop = default slot, 2) Named props z JSX: header={<Header/>}, 3) Compound components: <Card><Card.Header/></Card>. Compound components to najbliższy odpowiednik named slots — enkapsulują logikę i dają kontrolę nad układem. Children prop to najprostszy i najczęstszy wzorzec.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Strict Mode w React i dlaczego wywołuje podwójne renderowanie?', 'StrictMode w dev mode celowo podwójnie wywołuje render i efekty aby wykryć side effects w renderze, brak cleanup w efektach, użycie deprecjowanych API. Symuluje mount → unmount → mount. Jeśli komponent psuje się przy podwójnym renderze, ma bug (np. efekt bez cleanup, mutacja w renderze). Nie wpływa na produkcję — zero narzutu.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz route protection (auth guard) w Next.js?', 'Middleware (middleware.ts): interceptuje requesty, sprawdza cookie sesji, redirect do /login. Zaletą jest centralny punkt, działa dla wszystkich routes (config matcher). Alternatywa: sprawdzanie sesji w layout.tsx Server Component z redirect(). Nie polegaj na client-side sprawdzaniu — dane i tak mogą wyciec z Server Components bez middleware.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest ISR (Incremental Static Regeneration) i jak go konfigurujesz?', 'ISR pozwala odświeżać statyczne strony bez pełnego rebuildu. W App Router: export const revalidate = 3600 (sekundy) lub fetch(url, {next: {revalidate: 3600}}). On-demand: revalidatePath(''/blog'') lub revalidateTag(''posts'') w Server Action. Pierwsza wizyta po wygaśnięciu: stale content + background regeneration. Łączy zalety SSG (szybkość) z dynamicznymi danymi.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz stanem URL w React (search params, pathname)?', 'Next.js: useSearchParams(), usePathname(), useRouter(). Vanilla React: useSearchParams z react-router. Wzorzec: stan filtrowania/sortowania/paginacji w URL zamiast useState. Korzyści: shareability, back button, SSR. nuqs library upraszcza typowane search params z walidacją. Unikaj synchronizacji useState ↔ URL — to źródło bugów.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa useCallback w kontekście event handlerów?', 'useCallback memoizuje referencję funkcji. Bez niego każdy render tworzy nową funkcję. Ma sens gdy: przekazujesz handler do React.memo dziecka (nowa ref = rerender), handler jest w deps innego hooka. Bez tych przypadków useCallback to niepotrzebny narzut. W React 19+ z Compiler — useCallback jest dodawany automatycznie. Nie opakowuj każdej funkcji.', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest streaming SSR i jak różni się od klasycznego SSR?', 'Klasyczny SSR: serwer renderuje CAŁY HTML, wysyła jeden response. Streaming SSR: serwer wysyła HTML fragmentami (Transfer-Encoding: chunked). Suspense boundaries definiują granice streamingu. Korzyść: szybszy TTFB (użytkownik widzi shell natychmiast), progresywne ładowanie. Next.js App Router domyślnie streamuje. Wymaga infrastruktury obsługującej streaming (nie statyczny hosting).', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz loading i error states w Next.js App Router?', 'loading.tsx — automatyczny Suspense boundary dla segmentu route, wyświetla się podczas ładowania. error.tsx — automatyczny Error Boundary, otrzymuje error i reset(). not-found.tsx — wyświetla się przy notFound(). Zagnieżdżanie: każdy folder route może mieć własne. Granularne: <Suspense> w komponencie dla mniejszych fragmentów. Te pliki to convention over configuration.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz middleware pattern w Next.js?', 'middleware.ts w root projektu interceptuje KAŻDY request. Zastosowania: auth (redirect), i18n (locale detection), A/B testing, rate limiting. Config: export const config = {matcher: [''/dashboard/:path*'']}. Ograniczenia: działa na Edge Runtime (nie pełny Node.js), ograniczone API. Nie używaj do data fetching — tylko routing/redirect logic. Kolejność: middleware → route handler.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest taint API (experimental) w React?', 'taint API (experimental) oznacza obiekty/wartości jako „zanieczyszczone" — nie mogą być przekazane do Client Components. experimental_taintObjectReference(message, object) i taintUniqueValue. Cel: zapobieganie przypadkowemu wyciekowi danych wrażliwych (tokeny, hasła) z Server Components do klienta. Dodatkowa warstwa bezpieczeństwa na granicy server/client.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak realizujesz internationalizację (i18n) w Next.js App Router?', 'Podejścia: 1) next-intl — najpopularniejszy, middleware do locale detection, useTranslations() hook, Server Components support. 2) Subpath routing (/en/about, /pl/about) z [locale] dynamic segment. 3) Domain routing. Klucz: middleware wykrywa locale (header Accept-Language, cookie), redirect do odpowiedniego segmentu. Tłumaczenia w JSON, lazy loaded per locale.', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym różni się Options API od Composition API? Dlaczego Vue 3 promuje Composition?', 'Options API organizuje kod po typie (data, methods, computed, watch). Composition API organizuje po funkcjonalności — logika jednej feature w jednym miejscu. Powody przejścia: lepsza reużywalność (composables zamiast mixinów), pełna typizacja TypeScript, brak problemów z this, elastyczne grupowanie logiki. Options API nadal działa, ale Composition jest standardem.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się ref() od reactive()? Kiedy co wybrać?', 'ref() opakowuje dowolną wartość (prymityw/obiekt) w {value: ...} — dostęp przez .value w JS, automatyczne unwrapping w template. reactive() tworzy głęboko reaktywny proxy obiektu — bezpośredni dostęp bez .value. ref() preferowany: prymitywy, wymiana referencji, klarowność. reactive() dla obiektów bez potrzeby wymiany. Uwaga: destructuring reactive() traci reaktywność.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dlaczego destructuring reactive() traci reaktywność i jak to naprawić?', 'reactive() zwraca Proxy — destructuring kopiuje wartości prymitywne, tracąc Proxy. const {name} = reactive({name: ''Jan''}) — name to zwykły string. Rozwiązania: 1) toRefs() — konwertuje properties na ref, 2) storeToRefs() w Pinia, 3) używaj ref() od początku. To najczęstszy „gotcha" Vue 3 na rozmowach rekrutacyjnych.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj computed(), watch() i watchEffect(). Kiedy co stosować?', 'computed(): wartość pochodna, leniwa, cachowana, readonly (chyba że writable). watch(): reaguje na zmianę konkretnego źródła, ma dostęp do starej i nowej wartości, lazy domyślnie. watchEffect(): automatycznie śledzi zależności (jak useEffect bez deps array), eager, brak dostępu do starej wartości. computed do transformacji danych, watch do side effects z kontrolą, watchEffect do prostych efektów.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest script setup i jakie daje korzyści?', '<script setup> to compile-time sugar dla Composition API. Korzyści: mniej boilerplate (brak return, defineComponent), automatyczny expose propsów/emitów, lepszy TypeScript inference, tree-shaking top-level imports. Zmienne zadeklarowane na top-level są automatycznie dostępne w template. defineProps/defineEmits to compiler macros (nie importy).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj Pinia z Vuex. Dlaczego Pinia jest teraz standardem?', 'Pinia to oficjalny state manager Vue 3. Vs Vuex: brak mutations (bezpośrednia modyfikacja stanu), pełny TypeScript bez deklaracji typów, modularny (brak nested modules), lekki (1 KB), devtools integration. Vuex miał mutations→actions→getters co dodawało boilerplate. Pinia: defineStore z state, getters, actions — prostszy mental model. Vuex jest w maintenance mode.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają defineProps i defineEmits w script setup?', 'defineProps<{title: string; count?: number}>() definiuje typowane propsy. defineEmits<{(e: ''update'', value: string): void}>() definiuje typowane zdarzenia. Są compiler macros — nie wymagają importu. Runtime validation: defineProps({title: {type: String, required: true}}). withDefaults() dodaje wartości domyślne. Kompilator Vue zamienia je na odpowiedni Options API pod spodem.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest defineModel() i jak upraszcza v-model na komponentach?', 'defineModel() (Vue 3.4+) automatycznie tworzy prop + emit dla v-model. Zamiast ręcznego modelValue prop + update:modelValue emit — const model = defineModel<string>(). model.value = ''abc'' automatycznie emituje update. Wspiera named models: defineModel(''title''). Drastycznie redukuje boilerplate dla komponentów formularza z dwukierunkowym wiązaniem.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa provide/inject w Vue 3?', 'provide(key, value) w rodzicu udostępnia dane. inject(key, defaultValue) w dziecku/wnuku je pobiera. Działa przez drzewo komponentów — nie trzeba przekazywać propsów przez pośrednie poziomy. Typowanie: const key = Symbol() as InjectionKey<Type>. Reaktywność: provide ref() lub reactive() — inject dostanie reaktywną wartość. Odpowiednik Context API z Reacta.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są composables i jak się mają do mixinów?', 'Composables to funkcje reużywające logikę Composition API (np. useMouse, useFetch). Vs mixiny: brak name collision (jawne nazwy), jasne źródło danych, pełna typizacja TS, łatwe testowanie (zwykła funkcja). Konwencja: use* prefix. Composable może zwracać ref, computed, watch — pełny reaktywny kontekst. To główny mechanizm reużywania logiki w Vue 3.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Teleport w Vue i kiedy go stosujesz?', '<Teleport to="body"> renderuje zawartość w innym miejscu DOM niż pozycja w drzewie komponentów. Zastosowania: modale, tooltipy, notyfikacje — elementy wymagające pozycjonowania względem body (ucieczka z overflow:hidden, stacking context). Zachowuje logiczne powiązanie z rodzicem (props, events, DI). Warunkowy teleport: <Teleport :disabled="isMobile">.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Suspense w Vue 3 i jak go używasz?', '<Suspense> wyświetla #fallback slot dopóki async zależność w #default się nie załaduje. Wspiera: async setup() w komponentach, async komponenty (defineAsyncComponent). Dwa sloty: default (treść) i fallback (loading). onErrorCaptured w rodzicu łapie błędy. Experimental w Vue 3, ale szeroko używane z Nuxt 3. Deklaratywna obsługa loading states.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak Virtual DOM w Vue różni się od Reacta?', 'Oba używają vDOM, ale Vue optymalizuje kompilacją: compiler analizuje template i oznacza statyczne fragmenty (hoisting), dynamiczne bindingi (patch flags). React porównuje całe drzewo, Vue pomija znane statyczne części. Vue generuje zoptymalizowany render code z patch flags (TEXT, CLASS, STYLE). W efekcie Vue ma mniejszy overhead diffingu dla typowych szablonów.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa v-model na custom komponencie?', 'v-model="val" na komponencie to skrót dla :modelValue="val" @update:modelValue="val = $event". Komponent przyjmuje prop modelValue i emituje update:modelValue. Multiple v-models: v-model:title="t" v-model:content="c" (named models). Modyfikatory: v-model.trim, custom modifiers przez defineProps + modelModifiers. defineModel() od Vue 3.4 upraszcza to drastycznie.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie rodzaje slotów istnieją w Vue i kiedy ich używasz?', 'Default slot: <slot/> — domyślna treść z rodzica. Named slot: <slot name="header"/> — <template #header>. Scoped slot: <slot :item="item"/> — dziecko przekazuje dane do rodzica: <template #default="{item}">. Scoped slots kluczowe dla: tabel (custom row rendering), list, komponentów render-less. Slot to główny mechanizm composition w Vue templates.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opisz lifecycle hooks w Composition API.', 'onMounted, onUpdated, onUnmounted, onBeforeMount, onBeforeUpdate, onBeforeUnmount, onActivated/Deactivated (keep-alive), onErrorCaptured. W script setup nie ma beforeCreate/created — kod na top-level JEST created. Najczęstsze: onMounted (dostęp do DOM, fetch danych), onUnmounted (cleanup: listeners, timery). Mogą być wielokrotnie wywoływane (wielu onMounted w jednym komponencie).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest v-once, v-memo i kiedy je stosujesz?', 'v-once renderuje element raz — dalsze zmiany nie powodują rerenderowania. Użycie: statyczne treści (nagłówki, tekst prawny). v-memo=[deps] memoizuje fragment — rerender tylko gdy deps się zmienią. Użycie: lista z v-for gdzie większość elementów się nie zmienia. v-memo na v-for z key to odpowiednik React.memo. Nie nadużywaj — Vue i tak jest wydajny.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa keep-alive i kiedy go używasz?', '<KeepAlive> cachuje instancje komponentów zamiast je niszczyć. Przy powrocie do komponentu — stan jest zachowany (formularze, scroll position, dane). Props: include/exclude (filtrowanie po nazwie), max (limit cache). Lifecycle: onActivated/onDeactivated zamiast mounted/unmounted. Użycie: zakładki, kroki wizardów, nawigacja z powrotem do listy z pozycją scrollu.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest shallowRef i shallowReactive? Kiedy je stosujesz?', 'shallowRef: reaktywność tylko na .value (nie zagnieżdżone properties). shallowReactive: reaktywność tylko na pierwszym poziomie obiektu. Zastosowanie: duże obiekty gdzie śledzenie głębokich zmian jest kosztowne (lista 10k elementów, canvas state, dane z API). Przy modyfikacji zagnieżdżonych danych musisz ręcznie triggerować: triggerRef(ref) lub zamienić cały .value.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Nuxt 3 auto-imports?', 'Nuxt 3 automatycznie importuje: composables (ref, computed, useState, useFetch z Vue/Nuxt), komponenty z components/, composables z composables/, utility z utils/. Brak ręcznych importów w 90% kodu. Konfiguracja w nuxt.config.ts: imports.dirs. Typowanie generowane w .nuxt/. Korzyść: czystszy kod, szybszy development. Wada: mniej oczywiste zależności dla nowych w projekcie.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest universal rendering w Nuxt 3?', 'Universal rendering = SSR + client-side hydration. Serwer renderuje HTML (SEO, szybki FCP), klient hydruje (interaktywność). Nuxt 3 pozwala konfigurować per route: routeRules: {''/admin/**'': {ssr: false}}. Tryby: universal (SSR+hydration), spa (CSR only), static (pre-rendering). Hybrid rendering łączy je: strona główna SSR, dashboard SPA, blog pre-rendered.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają server routes w Nuxt 3?', 'Pliki w server/api/ i server/routes/ tworzą endpointy API automatycznie. server/api/users.get.ts → GET /api/users. Dostęp do request: defineEventHandler((event) => {...}). Obsługa: query params (getQuery), body (readBody), params, cookies. Działają na Nitro engine — deploy na Node, Cloudflare Workers, Vercel Edge. Brak potrzeby osobnego backendu dla prostych API.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useFetch vs useAsyncData w Nuxt 3?', 'useFetch(url) to wrapper na useAsyncData + $fetch. useAsyncData(key, () => fetchFn()) daje pełną kontrolę nad fetch logiką. Oba: deduplikacja na serwerze i kliencie, automatyczny transfer danych (payload), lazy option, immediate/watch. useFetch dla prostych GET, useAsyncData gdy potrzebujesz custom logiki (transformacja, multiple calls). Oba obsługują SSR + client hydration.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testujesz komponenty Vue z Vitest i Vue Test Utils?', 'Vue Test Utils: mount(Comp, {props, global: {plugins, stubs, provide}}). mount = full render, shallowMount = stub children. Szukanie: wrapper.find(''button''), wrapper.findComponent(Child). Triggery: wrapper.trigger(''click''), setValue(). Asynchroniczność: await nextTick(), await flushPromises(). Vitest zamiast Jest — szybszy, natywny ESM, kompatybilne API. Testuj zachowanie, nie implementację.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa system reaktywności Vue 3 pod spodem?', 'Vue 3 używa ES Proxy (zamiast Object.defineProperty z Vue 2). Proxy przechwytuje get (śledzenie zależności — track) i set (triggerowanie aktualizacji — trigger). Każdy efekt (render, watch, computed) ma Set zależności. Przy get: efekt dodaje się do dependency set. Przy set: wszystkie efekty w secie są reexecutowane. Proxy obsługuje dynamiczne property, Map/Set, tablice.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym się różni Vue 3 Proxy-based reactivity od Vue 2 Object.defineProperty?', 'Vue 2: Object.defineProperty nie wykrywa dodawania/usuwania properties (potrzebny Vue.set()), nie obsługuje natywnie Map/Set, problemy z tablicami (index assignment). Vue 3 Proxy: pełne przechwytywanie operacji, dynamiczne property, natywna obsługa kolekcji, lepsza wydajność dla dużych obiektów. To główny powód techniczny upgrade z Vue 2 do 3.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementujesz globalny error handling w Vue 3?', 'app.config.errorHandler = (err, instance, info) => {...} łapie błędy z komponentów, lifecycle hooks, event handlerów. onErrorCaptured w komponencie łapie błędy z dzieci (jak Error Boundary). Zwróć false aby zatrzymać propagację. Dla async: window.onunhandledrejection. Architektura: globalny handler loguje do Sentry, granularne onErrorCaptured wyświetlają fallback UI per sekcja.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają tranzycje (transitions) i animacje w Vue 3?', '<Transition> opakowuje element i dodaje klasy CSS przy wejściu/wyjściu: v-enter-from, v-enter-active, v-enter-to (analogicznie leave). <TransitionGroup> dla list z v-for. JavaScript hooks: @before-enter, @enter, @leave. Integracja z GSAP/anime.js przez hooks. Tryb: mode="out-in" (stary wychodzi, nowy wchodzi). Key na elemencie wymusza re-transition.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest defineAsyncComponent i jak realizujesz lazy loading komponentów?', 'defineAsyncComponent(() => import(''./Heavy.vue'')) tworzy komponent ładowany na żądanie. Opcje: loadingComponent, errorComponent, delay, timeout. Z <Suspense>: async component integruje się natywnie. W Nuxt 3: prefix Lazy — <LazyHeavyChart/> automatycznie lazy-loaduje. Użycie: modalne okna, ciężkie wykresy, edytory — wszystko co nie jest potrzebne na start.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz formularzami w Vue 3?', 'Podejścia: 1) v-model na inputach + reactive/ref (najprostsze), 2) VeeValidate + zod/yup (walidacja schematów), 3) FormKit (full-featured form framework). v-model daje dwukierunkowe wiązanie out of the box. Walidacja: computed z regexami (prosty), zod schema + VeeValidate useForm (zaawansowane). FormKit dodaje accessibility, multi-step, i18n — ciężki ale kompletny.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest watchEffect vs watch? Kiedy wolisz które?', 'watchEffect automatycznie śledzi wszystkie reaktywne zależności użyte wewnątrz — nie deklarujesz ich explicite. watch wymaga jawnego źródła i daje dostęp do oldValue/newValue. watchEffect lepszy: proste efekty z wieloma zależnościami, nie potrzebujesz starej wartości. watch lepszy: jedna konkretna zmienna, potrzebujesz porównania old/new, deep watch z kontrolą.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest toRefs() i toRef() i kiedy ich potrzebujesz?', 'toRefs(reactive) konwertuje każdy property reaktywnego obiektu na osobny ref — zachowuje reaktywność przy destructuring. toRef(reactive, ''key'') konwertuje jeden property. Typowe użycie: const {name, age} = toRefs(props) w Composition API, storeToRefs(store) w Pinia. Bez toRefs destructuring daje plain values — utrata reaktywności, najczęstszy bug początkujących.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak realizujesz komunikację między komponentami w Vue 3?', 'Sposoby: 1) props/emit (rodzic-dziecko), 2) provide/inject (przodek-potomek), 3) Pinia store (globalny stan), 4) composables (współdzielona logika), 5) template refs (imperatywny dostęp). Emits dla zdarzeń w górę, props dla danych w dół. Pinia gdy wiele komponentów współdzieli stan. Unikaj event bus — trudny do debugowania, Pinia jest lepszy.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa defineExpose w script setup?', 'W script setup nic nie jest domyślnie dostępne przez template ref rodzica. defineExpose({method, value}) jawnie eksponuje API komponentu. Przykład: child.value.focus() — zadziała tylko jeśli focus jest w defineExpose. To lepsza enkapsulacja niż Options API, gdzie wszystko było dostępne. Używaj oszczędnie — preferuj props/emit nad imperatywne wywołania.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest effectScope() i kiedy go używasz?', 'effectScope() grupuje reaktywne efekty (watch, watchEffect, computed) i pozwala je wszystkie zatrzymać jednym scope.stop(). Użycie: composables tworzone poza komponentem, cleanup logiki w bibliotekach, testowanie (scope izoluje efekty). Pinia używa effectScope wewnętrznie dla każdego store. W komponentach scope tworzony automatycznie i czyszczony przy unmount.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zoptymalizujesz wydajność dużej aplikacji Vue?', 'Checklist: shallowRef dla dużych danych, v-memo na v-for, KeepAlive dla tab/route cache, lazy loading komponentów, virtual scrolling (vue-virtual-scroller), computed zamiast metod w template, v-once dla statycznych fragmentów. Narzędzia: Vue DevTools Performance, Chrome DevTools. Unikaj: głębokich reactive obiektów bez potrzeby, watchers zamiast computed, zbyt wielu provide/inject.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Vapor Mode w Vue i co obiecuje?', 'Vapor Mode (w rozwoju) to alternatywny tryb kompilacji Vue eliminujący Virtual DOM. Kompiluje template do imperatywnych operacji DOM (jak Svelte/Solid). Korzyści: mniejszy runtime (~6 KB vs ~50 KB), szybsze aktualizacje, mniej pamięci. Kompatybilny z istniejącym Composition API. Opt-in per komponent. Idealny do lekkich widgetów i aplikacji wymagających ekstremalnej wydajności.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa routing w Vue Router 4?', 'createRouter({history: createWebHistory(), routes}) z typowanymi routes. Composition API: useRouter() (nawigacja), useRoute() (aktualne dane trasy). Navigation guards: beforeEach (globalny), beforeEnter (per route), onBeforeRouteLeave (w komponencie). Dynamic params: /user/:id → useRoute().params.id. Nested routes: children array. Lazy loading: component: () => import(''./View.vue'').', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz dynamiczne komponenty w Vue?', '<component :is="currentComponent"/> dynamicznie renderuje komponent na podstawie zmiennej. Przydatne: system tabów, konfigurowalny dashboard, formularze z dynamicznymi polami. Z KeepAlive: cachuje instancje przy przełączaniu. Z async: is może być defineAsyncComponent. Alternatywa: v-if/v-else-if dla kilku wariantów, ale <component :is> jest elastyczniejszy.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest plugin w Vue 3 i jak go tworzysz?', 'Plugin to obiekt z install(app, options) method. app.use(plugin) wywołuje install. Wewnątrz: app.component() (globalne komponenty), app.directive() (dyrektywy), app.provide() (globalne provide), app.config.globalProperties (globalne właściwości). Przykłady: i18n plugin, toast plugin, analytics. W Vue 3 preferuj composables nad globalProperties — lepsze typowanie i testowanie.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa custom directive w Vue 3?', 'Dyrektywa to obiekt z lifecycle hooks: created, beforeMount, mounted, beforeUpdate, updated, beforeUnmount, unmounted. Rejestracja: app.directive(''focus'', {mounted(el) {el.focus()}}). W template: v-focus. Argumenty: v-directive:arg.modifier="value". Shorthand: function syntax = mounted + updated. Użycie: DOM manipulation nie objęte Vue API (focus, tooltip, click-outside).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Nuxt 3 middleware i jakie ma typy?', 'Middleware w Nuxt 3 to funkcje uruchamiane przed nawigacją. Typy: 1) Named: middleware/auth.ts, używane per route (definePageMeta({middleware: ''auth''})), 2) Global: middleware/auth.global.ts — dla każdej route. defineNuxtRouteMiddleware((to, from) => {if (!loggedIn) return navigateTo(''/login'')}). Server middleware w server/middleware/ — dla HTTP requestów (logi, CORS, auth API).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz SSR-safe kod w Vue/Nuxt?', 'Problemy SSR: brak window/document na serwerze, różnice w renderze (hydration mismatch). Rozwiązania: onMounted dla client-only kodu (DOM API), <ClientOnly> komponent w Nuxt, import.meta.client / import.meta.server checks, useNuxtApp().$isHydrating. Unikaj: localStorage w setup, Math.random w template, Date.now bez stabilizacji. Testuj z SSR włączonym.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useState w Nuxt 3 i jak różni się od ref()?', 'useState(''key'', () => initialValue) to Nuxt composable tworzący SSR-friendly, współdzielony stan. Różnice od ref(): 1) Shared między komponentami (ten sam key = ten sam stan), 2) Serializable (przenoszony z serwera na klienta), 3) Przeżywa nawigację. ref() jest lokalny dla komponentu i nie przeżywa SSR. useState dla globalnego stanu bez Pinia, ref dla lokalnego.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz SEO w Nuxt 3?', 'useHead({title, meta: [{name: ''description'', content: ''...''}]}), useSeoMeta({ogTitle, ogDescription, ogImage}). Konfiguracja globalna: nuxt.config.ts app.head. Dynamiczne per strona: useHead w setup z computed title. Nuxt generuje SSR HTML z metatagami. Sitemap: @nuxtjs/sitemap. Robots: nuxt-simple-robots. Structured data: useSchemaOrg. SSR jest kluczowy — bez SSR meta tagi nie są widoczne dla crawlerów.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa system typów w Vue 3 z TypeScript?', 'Vue 3 to rewrite w TypeScript — pełna typizacja. defineProps<{name: string}>() — generics inference. ref<number>(0) — typowany ref. Computed auto-infers return type. defineEmits<{(e: ''change'', id: number): void}>() — typowane eventy. Pinia stores: pełne typy stanu, getterów, akcji. Problemem bywają dynamic slots i provide/inject — wymagają manualnych typów.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak realizujesz internacjonalizację (i18n) w Vue/Nuxt?', 'Vue: vue-i18n z createI18n({locale, messages}). useI18n() w Composition API: t(''key''), locale.value. Nuxt: @nuxtjs/i18n (wrapper na vue-i18n) z routingiem /en/about, /pl/about. Lazy loading tłumaczeń: każdy locale to osobny chunk. SEO: hreflang tagi automatycznie. Pluralizacja: t(''items'', count). Interpolacja: t(''hello'', {name: ''Jan''}). Fallback locale dla brakujących tłumaczeń.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Nuxt Content i kiedy go używasz?', 'Nuxt Content to moduł do zarządzania treścią (Markdown, YAML, JSON, CSV) jako file-based CMS. Pliki w content/ → queryContent API z filtrami, sortowaniem, paginacją. Renderowanie Markdown z Vue komponentami wewnątrz (MDC syntax). Użycie: blog, dokumentacja, landing page z CMS-like edycją. Alternatywa dla headless CMS gdy treść jest w repozytorium.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Nitro engine w Nuxt 3?', 'Nitro to server engine Nuxt 3 — uniwersalny, deploy-anywhere. Buduje server jako portable output dla: Node.js, Cloudflare Workers, Deno, Vercel, Netlify, AWS Lambda. Features: auto-imports server utils, file-based API routes, caching (defineCachedEventHandler), storage layer (useStorage). Nitro umożliwia Nuxt 3 bycie „full-stack framework" bez osobnego backendu.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testujesz Pinia stores?', 'Bez komponentu: const store = useCounterStore(createPinia()). Testuj actions: store.increment(); expect(store.count).toBe(1). Mockuj dependencies: createPinia() + overrideActions lub vi.mock. Z komponentem: mount(Comp, {global: {plugins: [createTestingPinia({initialState, stubActions: false})]}}). createTestingPinia automatycznie stubuje actions — ważne: stubActions: false jeśli chcesz je testować.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Opisz box model w CSS. Czym różni się content-box od border-box?', 'Box model: content → padding → border → margin. content-box (domyślny): width/height dotyczy tylko content — padding i border dodają do rozmiaru. border-box: width/height zawiera content + padding + border. Praktyka: *, *::before, *::after {box-sizing: border-box} w resecie — przewidywalne rozmiary. Margin nie wchodzi w box-sizing — zawsze na zewnątrz.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy używasz Flexbox a kiedy Grid? Podaj konkretne przypadki.', 'Flexbox: jednowymiarowy layout (wiersz LUB kolumna). Grid: dwuwymiarowy (wiersze I kolumny jednocześnie). Flexbox: navbar, toolbar, card footer z przyciskami, centrowanie. Grid: layout strony (header/sidebar/content/footer), galeria zdjęć, dashboard. Reguła: jeśli kontrolujesz jeden kierunek — Flexbox. Jeśli oba — Grid. Można łączyć: Grid na layout, Flex wewnątrz.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij specificity (specyficzność) selektorów CSS.', 'Specyficzność to „waga" selektora: inline style (1000) > ID (100) > class/attribute/pseudo-class (10) > element/pseudo-element (1). Przykład: #nav .link a = 100+10+1=111. !important nadpisuje wszystko (unikaj). Przy równej specyficzności wygrywa ostatnia reguła (cascade). Gotcha: .a.b (20) > .a (10) mimo tej samej ilości klas. Nie licz — rozumiej hierarchię.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są cascade layers (@layer) i jaki problem rozwiązują?', '@layer pozwala jawnie kontrolować kolejność kaskady. Reguły w warstwie o niższym priorytecie przegrywają z wyższą, niezależnie od specyficzności. Kolejność: @layer reset, base, components, utilities. Problem: biblioteka z selektorami o wyższej specyficzności nadpisuje nasze style. Z @layer: @layer lib {css z biblioteki} — łatwo nadpisujemy w wyższej warstwie.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są CSS custom properties (zmienne) i czym różnią się od zmiennych Sass?', 'CSS custom properties: --color: #333; użycie: var(--color, fallback). Różnice od Sass: 1) działają w runtime (dynamiczna zmiana przez JS/media queries), 2) podlegają kaskadzie i dziedziczeniu, 3) responsywne (zmiana w media query). Sass: compile-time, statyczne. Custom properties idealne do: tematów (dark mode), spacing scale, dynamicznych wartości. Sass do: obliczeń compile-time, mixins.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są container queries i jaki problem rozwiązują?', 'Container queries (@container) pozwalają stylizować element na podstawie rozmiaru jego kontenera (nie viewport). Problem: media queries = globalne — komponent w sidebar 300px i main 900px widzi ten sam viewport. Container queries: komponent adaptuje się do swojego kontenera. Wymaga: container-type: inline-size na rodzicu. @container (min-width: 400px) {.card {...}}.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij selektor :has() — do czego służy i dlaczego jest przełomowy?', ':has() to „parent selector" CSS — stylizuje element na podstawie jego dzieci/rodzeństwa. Przykłady: .card:has(img) {padding: 0} (karta z obrazkiem), form:has(:invalid) {border: red} (formularz z błędem), h2:has(+ p) {margin-bottom: 0} (h2 po którym jest p). Przełomowy bo CSS nigdy nie pozwalał selekcji w górę drzewa DOM.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opisz wartości position w CSS i kiedy każdej używasz.', 'static: domyślna, normalny flow. relative: offsetowany od swojej pozycji (kontekst dla absolute dzieci). absolute: wyjęty z flow, pozycjonowany względem najbliższego positioned przodka. fixed: względem viewport (nawigacja sticky, modal). sticky: normalny flow do progu scroll, potem „przykleja się" (nagłówki tabel, sekcji). Gotcha: fixed nie działa wewnątrz transform/filter (tworzy nowy containing block).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest stacking context (kontekst nakładania) i co go tworzy?', 'Stacking context to „warstwa" decydująca o kolejności rysowania elementów. Tworzy go: z-index na positioned element, opacity < 1, transform, filter, will-change, position: fixed/sticky. Ważne: z-index działa TYLKO w ramach tego samego kontekstu — element z z-index: 9999 w niższym kontekście przegra z z-index: 1 w wyższym. Debuguj przez DevTools layers panel.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest BEM i jak pomaga w organizacji CSS?', 'BEM: Block__Element--Modifier. Block: samodzielny komponent (.card). Element: część bloku (.card__title). Modifier: wariant (.card--featured). Korzyści: niska specyficzność (same klasy), jasna zależność, brak kolizji nazw. Wady: długie nazwy, verbose. Alternatywy: CSS Modules, Tailwind, styled-components. BEM nadal popularny w dużych projektach bez CSS-in-JS.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest semantyczny HTML i dlaczego ma znaczenie?', 'Semantyczny HTML to użycie elementów zgodnie z ich znaczeniem: <header>, <nav>, <main>, <article>, <section>, <aside>, <footer> zamiast <div>. Znaczenie: 1) Dostępność — screen readers identyfikują strukturę, 2) SEO — wyszukiwarki rozumieją treść, 3) Czytelność kodu. <article> = niezależna treść, <section> = tematyczna grupa, <aside> = treść poboczna.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie role ARIA są najważniejsze i kiedy ich używasz?', 'ARIA uzupełnia semantykę gdy HTML nie wystarczy. Kluczowe role: role="button" (div jako przycisk), role="dialog" (modal), role="alert" (komunikat), role="navigation" (nawigacja). Stany: aria-expanded, aria-selected, aria-hidden, aria-live. Zasada: preferuj natywny HTML (<button> nie potrzebuje role="button"). ARIA to last resort — nadmiar ARIA jest gorszy niż brak.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zapewnisz dostępność (accessibility) formularza?', 'Checklist: <label for="id"> powiązany z każdym input, aria-describedby dla opisów/błędów, aria-invalid="true" + aria-errormessage dla walidacji, fieldset + legend dla grup, jasny focus order (tabindex), widoczny focus ring, komunikaty błędów z role="alert" (aria-live). Nie usuwaj focus outline — zamiast tego stylizuj :focus-visible. Testuj z klawiatury i screen readerem.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest podejście mobile-first i dlaczego jest preferowane?', 'Mobile-first: bazowe style dla mobile, media queries dodają style dla większych ekranów (min-width). Desktop-first: bazowe dla desktopu, nadpisujesz w dół (max-width). Mobile-first korzyści: progresywne wzbogacanie (mobile = podstawa), mniejszy CSS (mobile dostaje mniej reguł), wymusza prostotę. min-width jest addytywne (dodajesz), max-width jest subtractywne (usuwasz).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa clamp(), min() i max() w CSS?', 'clamp(min, preferred, max): wartość rośnie/maleje z preferred ale nie wychodzi poza min/max. Idealne do fluid typography: font-size: clamp(1rem, 2.5vw, 2rem). min(): wybiera mniejszą wartość, max(): większą. width: min(90%, 1200px) = responsywny max-width bez media query. Te funkcje eliminują wiele media queries i tworzą płynne, responsywne layouty.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się transition od animation w CSS?', 'Transition: reaguje na zmianę stanu (hover, class toggle). Definiuje przejście od A do B. Wymaga triggera. animation: odgrywa się samodzielnie, definiuje @keyframes z wieloma krokami. Nie wymaga triggera (animation-play-state). Transition: proste efekty hover, opacity, transform. Animation: nieskończone pętle, złożone sekwencje, loading spinnery, pojawianie się elementów.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak tworzyć wydajne animacje CSS? Które właściwości animować?', 'Wydajne (GPU-accelerated, nie triggerują layout/paint): transform (translate, scale, rotate) i opacity. Powolne (triggerują layout): width, height, top, left, margin, padding. Powolne (triggerują paint): color, background, box-shadow. will-change: transform informuje przeglądarkę o planowanej animacji (oszczędnie!). Zasada: animuj TYLKO transform i opacity — reszta przez triki (scale zamiast width).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są pseudo-elementy ::before i ::after? Podaj praktyczne zastosowania.', 'Pseudo-elementy tworzą wirtualne elementy w DOM (nie istnieją w HTML). Wymagają content: "". Zastosowania: dekoracyjne elementy (linie, ikony), clearfix (legacy), CSS-only tooltips, overlay na obrazkach, numeracja custom list, dekoracyjne cudzysłowy. Ważne: nie mają semantyki (screen reader ich nie czyta), nie działają na void elements (<input>, <img>).', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są CSS logical properties i dlaczego warto ich używać?', 'Logical properties używają kierunków inline/block zamiast left/right/top/bottom. margin-inline-start zamiast margin-left, padding-block zamiast padding-top + padding-bottom. Korzyść: automatyczne odwrócenie w RTL (arabski, hebrajski) — bez duplikowania styli. Inline = kierunek tekstu, block = prostopadły. Przyszłość CSS — adopcja rośnie, wspierane we wszystkich przeglądarkach.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Flexbox — wyjaśnij główną i poprzeczną oś.', 'Flexbox ma main axis (kierunek flex-direction) i cross axis (prostopadła). Row: main = pozioma, cross = pionowa. Column: odwrotnie. justify-content wyrównuje po main axis. align-items po cross axis. flex-grow/shrink/basis kontrolują rozmiar na main axis. gap dodaje odstępy. Gotcha: align-items: stretch (domyślna) rozciąga dzieci na cross axis — może zaskakiwać.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest flex-grow, flex-shrink i flex-basis? Jak działa shorthand flex?', 'flex-basis: początkowy rozmiar (przed grow/shrink). flex-grow: proporcja dodatkowej przestrzeni do przydzielenia. flex-shrink: proporcja kurczenia gdy brak miejsca. flex: 1 = flex: 1 1 0% (rośnie, kurczy się, bazuje na 0). flex: auto = flex: 1 1 auto (bazuje na content). flex: none = flex: 0 0 auto (sztywny). Gotcha: flex-basis: 0 vs auto daje różne rozkłady przestrzeni.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wycentrować element pionowo i poziomo w CSS? Podaj 3 sposoby.', '1) Flexbox: display: flex; justify-content: center; align-items: center; (najczęstszy). 2) Grid: display: grid; place-items: center; (najkrótszy). 3) Position: position: absolute; inset: 0; margin: auto; (element z width/height). Bonus: translate: transform: translate(-50%, -50%) + top/left 50% (legacy). Flexbox/Grid to dzisiejszy standard — proste, czytelne, responsywne.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest CSS Grid i jak definiujesz grid template?', 'Grid: display: grid na kontenerze. grid-template-columns: repeat(3, 1fr) — 3 równe kolumny. grid-template-rows: auto 1fr auto. Jednostka fr: ułamek wolnej przestrzeni. grid-gap/gap: odstępy. Placement: grid-column: 1 / 3 (span 2 kolumny). Named lines i areas: grid-template-areas: "header header" "sidebar main". Subgrid: dziecko dziedziczy grid rodzica.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest subgrid i jaki problem rozwiązuje?', 'Subgrid pozwala dziecku grid kontenera odziedziczyć linie (tracks) rodzica. Problem: bez subgrid wewnętrzny grid jest niezależny — nagłówki kart w rzędzie mogą mieć różne wysokości. Z subgrid: dziecko grid-template-rows: subgrid wyrównuje swoje rzędy do rodzica. Rozwiązuje alignment w kartach, formularzach, tabelkach. Wspierany we wszystkich nowoczesnych przeglądarkach.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest margin collapse i kiedy występuje?', 'Margin collapse: pionowe marginesy sąsiadujących elementów blokowych łączą się — wygrywamy większy, nie suma. Występuje: sąsiednie rodzeństwo, rodzic z pierwszym/ostatnim dzieckiem (jeśli brak padding/border), pusty element. NIE występuje: elementy flex/grid, floated, inline-block, z overflow nie-visible. Najczęstsza pułapka: margin dziecka „wychodzi" z rodzica — dodaj padding/border/overflow na rodzicu.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zrealizujesz responsywny design bez media queries?', 'Techniki: 1) clamp() dla font-size/padding, 2) Flex wrap: flex-wrap: wrap + flex: 1 1 300px (karty), 3) Grid: repeat(auto-fit, minmax(250px, 1fr)), 4) min()/max(): width: min(100%, 800px), 5) Aspect-ratio: aspect-ratio: 16/9. Te podejścia tworzą „intrinsic design" — elementy adaptują się do dostępnej przestrzeni bez breakpointów. Media queries dla większych zmian layoutu.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest :focus-visible i czym różni się od :focus?', ':focus aktywuje się przy każdym focusie (klik myszy też). :focus-visible aktywuje się tylko gdy focus jest „widoczny" — klawiatura, ale nie klik myszy. Rozwiązuje problem: outline przy kliknięciu przyciskiem myszy irytuje użytkowników, ale jest kluczowy dla dostępności klawiatury. Best practice: button:focus-visible { outline: 2px solid blue; } zamiast button:focus.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa kaskada CSS? Jakie są źródła styli i ich priorytety?', 'Kolejność (od najważniejszej): 1) !important user agent, 2) !important user, 3) !important author @layer, 4) !important author, 5) inline style, 6) author @layer (od ostatniego), 7) author (bez layer), 8) user, 9) user agent. Wewnątrz tego samego źródła: specyficzność, potem kolejność w kodzie. @layer odwraca kolejność !important (wewnętrzna warstwa > zewnętrzna).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest prefers-color-scheme i jak go używasz?', '@media (prefers-color-scheme: dark) {...} wykrywa preferencje systemowe użytkownika. Best practice: definiuj CSS custom properties per schemat: :root {--bg: white;} @media (prefers-color-scheme: dark) {:root {--bg: #1a1a1a;}}. Łącz z data-theme atrybutem dla ręcznego toggle. prefers-reduced-motion analogicznie — wyłącz animacje dla użytkowników z epilepsją/vestibular disorders.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest prefers-reduced-motion i jak go implementujesz?', '@media (prefers-reduced-motion: reduce) eliminuje/upraszcza animacje dla użytkowników, którzy tego życzą (epilepsja, choroba lokomocyjna). Implementacja: @media (prefers-reduced-motion: reduce) { *, *::before, *::after { animation-duration: 0.01ms !important; transition-duration: 0.01ms !important; } }. Alternatywa: definiuj animacje tylko w (prefers-reduced-motion: no-preference).', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest aspect-ratio w CSS i jakie ma zastosowania?', 'aspect-ratio: 16/9 utrzymuje proporcje elementu bez padding-top hack. Zastosowania: responsywne video/iframe kontenery, obrazki placeholder (zapobieganie CLS), karty o stałych proporcjach. Działa z: width (height auto-computed), height (width auto-computed), oba (aspect-ratio ignorowany). Zastępuje stary hack: padding-top: 56.25% (16:9) + absolute child.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zapobiegasz CLS (Cumulative Layout Shift) w CSS?', 'CLS to metryka Core Web Vitals mierząca niespodziewane przesunięcia layoutu. Zapobieganie: 1) width/height lub aspect-ratio na obrazkach/video, 2) font-display: optional lub swap + size-adjust, 3) min-height na dynamicznie ładowanych sekcjach, 4) transform zamiast top/left do animacji, 5) content-visibility: auto z contain-intrinsic-size. Biggest offenders: obrazki bez wymiarów, późne ładowanie fontów, wstrzykiwane banery.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest overflow i jak tworzy Block Formatting Context?', 'overflow kontroluje co dzieje się z treścią przekraczającą rozmiar: visible (domyślna — wylewa się), hidden (ukryta), scroll (scrollbar), auto (scrollbar gdy potrzebny). overflow inny niż visible tworzy BFC — blokuje margin collapse, zawiera floated children. Gotcha: overflow: hidden na rodzicu z position: sticky dzieckiem — sticky nie zadziała.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest viewport unit i jakie nowe jednostki istnieją?', 'Klasyczne: vw/vh (1% viewport width/height). Problem: vh na mobile nie uwzględnia paska adresu. Nowe: svh (small viewport — z paskiem), lvh (large viewport — bez paska), dvh (dynamic — zmienia się). svw/lvw/dvw analogicznie. dvh najczęściej pożądany — 100dvh = pełna widoczna wysokość. Jednostki vi/vb (inline/block) dla logical properties.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa CSS Grid auto-placement i kiedy jest przydatne?', 'Grid automatycznie umieszcza elementy w wolnych komórkach: grid-auto-flow: row (domyślna — wypełnia wierszami), column, dense (wypełnia dziury). Dense: elementy wchodzą w wolne miejsca niezależnie od kolejności DOM — przydatne dla galerii/masonry. Auto-placement + repeat(auto-fill/auto-fit, minmax()) = w pełni responsywna siatka bez media queries i bez określania pozycji elementów.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się auto-fill od auto-fit w CSS Grid?', 'Oba automatycznie tworzą kolumny: repeat(auto-fill/auto-fit, minmax(200px, 1fr)). Różnica widoczna gdy elementów jest mniej niż kolumn: auto-fill tworzy puste kolumny (zachowuje tracks). auto-fit collapse''uje puste kolumny (elementy rozciągają się). auto-fit częstszy — elementy wypełniają kontener. auto-fill gdy chcesz zachować stałą siatkę.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa display: contents i kiedy go używasz?', 'display: contents sprawia, że element „znika" z layout — jego dzieci stają się bezpośrednimi dziećmi rodzica layoutowego. Zastosowanie: wrapper div wymagany przez komponent, ale Grid/Flex powinien widzieć grandchildren. Uwaga: element traci box (margin, padding, border) i może tracić semantykę (accessibility issues z elementami jak button). Używaj ostrożnie.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest content-visibility i jak poprawia wydajność?', 'content-visibility: auto mówi przeglądarce, że element poza viewport może pominąć rendering (layout, paint). Przeglądarka renderuje go dopiero gdy zbliży się do viewport. Wymaga contain-intrinsic-size do szacowania rozmiaru (zapobieganie CLS). Idealny dla długich list, artykułów, komentarzy. Może poprawić initial render time o 50%+ dla stron z dużą ilością treści.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest HTML dialog element i jak go używasz?', '<dialog> to natywny element modalny. dialog.showModal() otwiera jako modal z backdrop, dialog.show() jako non-modal. Natywne: focus trapping, Escape zamyka, ::backdrop pseudo-element. Zwraca wartość: <form method="dialog"> zamyka dialog z returnValue. Korzyści: dostępność out of the box, brak potrzeby aria-modal, prawidłowy focus management. Zastępuje 90% potrzeb na custom modale.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest popover API w HTML i czym różni się od dialog?', 'popover attribute to nowe API dla non-modal overlay: tooltips, dropdowns, menus. <button popovertarget="menu"><div id="menu" popover>. Auto dismissal (klik poza), brak focus trappingu (nie jest modal), stacking powyżej content (top layer). Dialog = modal (blokuje interakcję). Popover = non-modal (uzupełnia interakcję). Popover zastępuje custom dropdown/tooltip JS logic.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz niestandardowe fonty i optymalizujesz ich ładowanie?', '@font-face z format() deklaruje font. font-display: swap (FOUT — tekst systemowy → custom), optional (jeśli nie załaduje szybko — pomija). Preload: <link rel="preload" href="font.woff2" as="font" crossorigin>. Subsetting: tylko potrzebne znaki (unicode-range). WOFF2 format (~30% mniejszy). size-adjust, ascent-override zapobiegają CLS. Self-hosting szybszy niż Google Fonts.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest :where() i :is() w CSS? Jak wpływają na specyficzność?', ':is(.a, .b) {color: red} = .a {color: red} .b {color: red}. Specyficzność :is() = najwyższa z listy. :where() działa identycznie, ale ma ZERO specyficzności — idealne do resetów i default styli łatwych do nadpisania. Użycie: :where(article, section, aside) h2 {...} — łatwo nadpiszesz. :is() zachowuje naturalną specyficzność. Oba eliminują duplikację selektorów.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementujesz dark mode w CSS?', 'Podejścia: 1) prefers-color-scheme media query (automatycznie z OS), 2) data-theme atrybut na <html> + CSS custom properties, 3) class toggle (.dark). Best practice: łącz — domyślnie OS preference, toggle nadpisuje. Zdefiniuj kolory jako custom properties: :root {--bg: #fff;} [data-theme=dark] {--bg: #1a1a1a;}. Używaj semantycznych nazw (--bg, --text-primary), nie --white/--black.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest color-scheme i jak się ma do prefers-color-scheme?', 'color-scheme: light dark informuje przeglądarkę, że strona obsługuje oba schematy. Przeglądarka automatycznie dostosowuje: scrollbary, formularze, <select>, ::selection. Meta tag: <meta name="color-scheme" content="light dark">. prefers-color-scheme to media query do custom styli, color-scheme to deklaracja wsparcia dla UA styli. Oba powinny być używane razem.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa CSS nesting (zagnieżdżanie)?', 'Natywne CSS nesting: .card { & .title { color: blue; } &:hover { background: gray; } @media (width > 768px) { padding: 2rem; } }. & reprezentuje rodzica. Bez &: selektor potomka. Korzyści: grupowanie powiązanych reguł, czytelność, brak potrzeby preprocesora. Różnica od Sass: & wymagane na początku selektora (w starszych wersjach spec). Wspierane we wszystkich nowoczesnych przeglądarkach.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest contain CSS property i jak wpływa na wydajność?', 'contain informuje przeglądarkę, że element jest izolowany: contain: layout (nie wpływa na layout rodzeństwa), size (nie zmienia rozmiaru), paint (nie maluje poza box), style (counters izolowane). contain: strict = size layout paint style. Korzyść: przeglądarka może optymalizować rendering — zmiany wewnątrz nie wymagają przeliczania reszty strony. Używaj z content-visibility.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementujesz responsywną nawigację (hamburger menu)?', 'Mobile: ukryty nav, hamburger button (aria-expanded, aria-controls), klik toggleuje visibility. Desktop: widoczny nav, ukryty hamburger. CSS: @media (min-width: 768px) {.nav {display: flex;} .hamburger {display: none;}}. Accessibility: button nie div, aria-expanded="true/false", focus trap w otwartym menu, Escape zamyka. Animacja: transform: translateX() (wydajne) zamiast left/width.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest inset CSS property?', 'inset to shorthand dla top + right + bottom + left. inset: 0 = top: 0; right: 0; bottom: 0; left: 0 (popularny pattern z position: absolute/fixed do fullscreen overlay). inset: 10px 20px = top/bottom: 10px, left/right: 20px. Logical equivalents: inset-block (top/bottom), inset-inline (left/right). Drastycznie skraca pozycjonowanie elementów. Wspierane we wszystkich przeglądarkach.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak optymalizujesz obrazki na stronie webowej?', 'Format: WebP/AVIF (mniejsze niż JPEG/PNG). <picture> z <source> per format. Lazy loading: loading="lazy" (natywne). Responsive: srcset + sizes dla różnych viewportów. Wymiary: zawsze podawaj width/height (zapobiega CLS). Decoding: decoding="async". CSS: object-fit: cover/contain dla elastycznego skalowania. CDN z automatyczną optymalizacją (Cloudinary, imgix). fetchpriority="high" dla hero image.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest scroll-snap w CSS i jak go konfigurujesz?', 'scroll-snap tworzy „przyciąganie" scrollu do punktów. Kontener: scroll-snap-type: x mandatory (oś + tryb). Dzieci: scroll-snap-align: start/center/end. mandatory: zawsze przyciąga do punktu, proximity: tylko gdy blisko. Zastosowania: karuzele, galerie, strony full-screen, horizontal scrolling. scroll-padding na kontenerze: offset dla fixed header. Natywna alternatywa dla carousel JS bibliotek.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
